sql:
SELECT MIN(actual_cost) AS min_actual_cost
FROM maintenance_activities
WHERE status = 'Completed' AND performed_by = 'user1';

SELECT relationship_status 
FROM asset_relationships 
WHERE relationship_id = 1;

SELECT asset_id
FROM stormwater_quality
WHERE deviation > 0;

SELECT AVG(value) AS avg_turbidity
FROM stormwater_quality
WHERE parameter = 'Turbidity';

external_knowledge:
- 'deviated from the standard' means the average deviation is greater than 0;
- 'severity of deviation' refers to the magnitude of the average deviation;
- 'the past 6 months' refers to the time period between the current date and 6 months ago.

sql:
SELECT outfall_date, water_quality
FROM outfalls
WHERE discharge_rate > 5.0;

external_knowledge:
Drainage assets refer to physical structures that help manage stormwater runoff; 
Maintenance activities include inspections, repairs, and cleaning of these assets;
Stormwater quality data represents measurements of water parameters such as pH and turbidity;
A high average deviation from standard quality values may indicate poor water quality.

- Drainage assets refer to infrastructure designed to manage and redirect water runoff; 
- Standard value refers to the expected or normal value for water quality; 
- Deviation from the standard value indicates how much the actual water quality differs from the expected value.

sql:
SELECT parameter, AVG(deviation) AS average_deviation
FROM stormwater_quality
GROUP BY parameter;

SELECT COUNT(*) 
FROM outfalls 
WHERE environmental_impact = 'Medium';
